// PBFT Consensus Phases
class PBFTNode {
    int nodeId;
    List<Message> prepareMessages = new ArrayList<>();
    List<Message> commitMessages = new ArrayList<>();

    // Phase 1: Pre-prepare (from leader)
    void prePrepare(Message msg, int sequence) {
        if (isValidSequence(sequence)) {
            broadcastToAll(PrepareMessage(msg, sequence));
        }
    }

    // Phase 2: Prepare (from replicas)
    void prepare(PrepareMessage msg) {
        prepareMessages.add(msg);
        if (prepareMessages.size() >= 2 * f) {
            broadcastToAll(CommitMessage(msg.sequence));
        }
    }

    // Phase 3: Commit
    void commit(CommitMessage msg) {
        commitMessages.add(msg);
        if (commitMessages.size() >= 2 * f + 1) {
            executeRequest(msg.request);
            respondToClient();
        }
    }
}
